const cfg = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.sentProjects) staticData.sentProjects = {};
staticData.currentRunProjects = [];

const retentionDays = Number(cfg.retentionDays || 120);
const cutoff = Date.now() - retentionDays * 86400000;

for (const [projectId, value] of Object.entries(staticData.sentProjects)) {
  const seenAt = value && value.seenAt ? Date.parse(value.seenAt) : null;
  if (!seenAt || seenAt < cutoff) delete staticData.sentProjects[projectId];
}

return [{ json: cfg }];

function clean(s) {
  return String(s || '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#34;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function abs(url) {
  if (!url) return null;
  if (url.startsWith('http')) return url;
  if (url.startsWith('/')) return `https://legislacja.gov.pl${url}`;
  return `https://legislacja.gov.pl/${url}`;
}

function parseDatePL(val) {
  if (!val) return null;
  const s = String(val).trim();
  let m = s.match(/(\d{2})-(\d{2})-(\d{4})/);
  if (!m) m = s.match(/(\d{2})\.(\d{2})\.(\d{4})/);
  return m ? new Date(`${m[3]}-${m[2]}-${m[1]}T00:00:00Z`) : null;
}

const raw = $input.first().json;
const html = typeof raw === 'string'
  ? raw
  : (raw.body || raw.data || raw.html || raw.response || '');

if (!html) {
  return [{ json: { error: true, stage: 'fetch-homepage', message: 'Brak HTML z homepage.', bodyPreview: '' } }];
}

if (html.includes('Żądanie nie może zostać zrealizowane') || html.includes('Request Rejected')) {
  return [{
    json: {
      error: true,
      stage: 'fetch-homepage',
      message: 'Serwis odrzucił żądanie do strony głównej.',
      bodyPreview: html.slice(0, 500)
    }
  }];
}

const sectionMatch = html.match(/Ostatnio dodane projekty([\s\S]*?)Rozwiń lub zwiń menu projektów/i);
const section = sectionMatch ? sectionMatch[1] : html;

const cfg = $('Config').first().json;
const daysLookback = Number(cfg.daysLookback || 14);
const now = new Date();
const out = [];
const seen = new Set();

const regex = /<tr>[\s\S]*?<a href="([^"]*\/projekt\/[^"]*)"[^>]*>([\s\S]*?)<\/a>[\s\S]*?<td[^>]*class="text-right"[^>]*>\s*(\d{2}-\d{2}-\d{4}|\d{2}\.\d{2}\.\d{4})\s*<\/td>[\s\S]*?<\/tr>/gsi;
let m;
while ((m = regex.exec(section)) !== null) {
  const projectUrl = abs(m[1]);
  const title = clean(m[2]);
  const dateCreated = m[3];
  const created = parseDatePL(dateCreated);
  const ageDays = created ? Math.floor((now - created) / 86400000) : null;
  if (ageDays !== null && ageDays > daysLookback) continue;
  if (!projectUrl || !title || seen.has(projectUrl)) continue;
  seen.add(projectUrl);
  out.push({
    json: {
      projectUrl,
      titleFromList: title,
      dateCreatedFromList: dateCreated,
      fromEmail: cfg.fromEmail,
      toEmail: cfg.toEmail,
      daysLookback: cfg.daysLookback,
      scoreThreshold: cfg.scoreThreshold,
      batchSize: cfg.batchSize,
      waitSeconds: cfg.waitSeconds,
      retentionDays: cfg.retentionDays
    }
  });
}

if (!out.length) {
  return [{
    json: {
      error: true,
      stage: 'extract-recent-projects',
      message: 'Nie znaleziono linków do projektów w sekcji Ostatnio dodane projekty.',
      bodyPreview: section.slice(0, 700)
    }
  }];
}

return out;

function parseDatePL(val) {
  if (!val) return null;
  const s = String(val).trim();
  let m = s.match(/(\d{2})-(\d{2})-(\d{4})/);
  if (!m) m = s.match(/(\d{2})\.(\d{2})\.(\d{4})/);
  return m ? new Date(`${m[3]}-${m[2]}-${m[1]}T00:00:00Z`) : null;
}

function cleanText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function normalizeKeyChanges(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map(v => cleanText(v).replace(/[.;]+$/g, ''))
    .filter(Boolean)
    .slice(0, 4);
}

function normalizeComparable(value) {
  return cleanText(value)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function overlapRatio(summary, title) {
  const summaryTokens = Array.from(new Set(normalizeComparable(summary).split(' ').filter(t => t.length > 3)));
  const titleTokens = Array.from(new Set(normalizeComparable(title).split(' ').filter(t => t.length > 3)));
  if (!summaryTokens.length || !titleTokens.length) return 0;
  const titleSet = new Set(titleTokens);
  const overlap = summaryTokens.filter(token => titleSet.has(token)).length;
  return overlap / Math.max(1, Math.min(summaryTokens.length, titleTokens.length));
}

function looksTitleLike(summary, title) {
  const s = cleanText(summary);
  const t = cleanText(title);
  if (!s) return true;
  const ns = normalizeComparable(s);
  const nt = normalizeComparable(t);
  if (nt && ns.startsWith(nt.slice(0, Math.min(nt.length, 140)))) return true;
  if (/^projekt\s+(ustawy|rozporzadzenia|rozporządzenia|uchwaly|uchwały)\b/i.test(s) && overlapRatio(s, t) >= 0.6) return true;
  return false;
}

function trimSentence(text, maxLen = 520) {
  let s = cleanText(text);
  if (!s) return '';
  if (s.length <= maxLen) return s;
  s = s.slice(0, maxLen).replace(/\s+\S*$/, '');
  return s.replace(/[,:;\-–—\s]+$/, '') + '...';
}

function lowerFirst(text) {
  const s = cleanText(text);
  if (!s) return '';
  return s.charAt(0).toLowerCase() + s.slice(1);
}

function ensureSentence(text) {
  const s = cleanText(text).replace(/[.;:,\s]+$/, '');
  if (!s) return '';
  return /[.!?]$/.test(s) ? s : `${s}.`;
}

function genericPhraseHits(text) {
  const summary = normalizeComparable(text);
  if (!summary) return 0;
  const phrases = [
    'wprowadza nowe rozwiazania',
    'ma na celu poprawe',
    'ma na celu wprowadzenie zmian',
    'ma na celu zmiane',
    'ma wplynac na',
    'usprawnienie systemu',
    'najwazniejsze zmiany dotycza',
    'w tym zakresie',
    'poprawe jakosci i dostepnosci',
    'projekt ten ma na celu',
    'projekt ten wprowadza',
    'projekt ma rowniez na celu'
  ];
  return phrases.filter(p => summary.includes(p)).length;
}

function hasConcreteSignals(text) {
  const summary = cleanText(text);
  if (!summary) return false;
  if (/\d/.test(summary)) return true;
  return /(fundusz|program|tabel|stawk|warto(?:ść|sci)|limit|warun(?:ek|ki)|beneficjent|organizacj(?:e|i)|hospitalizac|weekend|paszport|dow[oó]d|o[łl]ow|termomoderniz|stop smog|po[żz]ytku publicznego|świadcze|personel|dokument publiczn|nara[żz]eni|krwi|komisji|wynagrodze[nń])/i.test(summary);
}

function looksTooGeneric(summary, keyChanges) {
  const text = cleanText(summary);
  if (!text) return true;
  const hits = genericPhraseHits(text);
  const concrete = hasConcreteSignals(text);
  const hasChanges = normalizeKeyChanges(keyChanges).length > 0;
  if (hits >= 2 && !concrete) return true;
  if (hits >= 1 && !concrete && hasChanges) return true;
  if (/^projekt dotyczy:/i.test(text)) return true;
  return false;
}

function composeSummary(author, keyChanges, fallbackSummary) {
  const changes = normalizeKeyChanges(keyChanges);
  const cleanAuthor = cleanText(author);
  const safeFallback = cleanText(fallbackSummary);
  if (changes.length) {
    const first = lowerFirst(changes[0]);
    const rest = changes.slice(1, 3).map(lowerFirst);
    const intro = cleanAuthor
      ? ensureSentence(`${cleanAuthor} przygotował projekt, który przewiduje ${first}`)
      : ensureSentence(`Projekt przewiduje ${first}`);
    let second = '';
    if (rest.length === 1) {
      second = ensureSentence(`Dodatkowo projekt obejmuje ${rest[0]}`);
    } else if (rest.length > 1) {
      second = ensureSentence(`Dodatkowo projekt obejmuje ${rest.join(' oraz ')}`);
    }
    if (safeFallback && !looksTitleLike(safeFallback, '') && !looksTooGeneric(safeFallback, [])) {
      const fallbackSentence = ensureSentence(safeFallback);
      return trimSentence([intro, second, fallbackSentence].filter(Boolean).join(' '));
    }
    return trimSentence([intro, second].filter(Boolean).join(' '));
  }
  if (cleanAuthor && safeFallback) {
    return trimSentence(`Autorem projektu jest ${cleanAuthor}. ${safeFallback}`);
  }
  return trimSentence(safeFallback);
}

function ensureAuthor(summary, author) {
  const cleanAuthor = cleanText(author);
  if (!summary || !cleanAuthor) return summary;
  const normalizedSummary = normalizeComparable(summary);
  const normalizedAuthor = normalizeComparable(cleanAuthor);
  if (normalizedSummary.includes(normalizedAuthor)) return summary;
  return trimSentence(`Autorem projektu jest ${cleanAuthor}. ${summary}`);
}

const payload = $json;
if (!payload || payload.error || !payload.url) return { json: {} };

const ai = payload.output && typeof payload.output === 'object' ? payload.output : null;
const rawAiSummary = cleanText(ai?.summary || '');
const aiAuthor = cleanText(ai?.author || '');
const aiKeyChanges = normalizeKeyChanges(ai?.keyChanges);
const aiSourceQuality = cleanText(ai?.sourceQuality || '');

const fallbackSummary = trimSentence(payload.fallbackSummary || payload.summary || `Projekt dotyczy: ${payload.title || payload.url}.`);
const applicant = cleanText(payload.applicant || aiAuthor);
let aiSummary = rawAiSummary && !looksTitleLike(rawAiSummary, payload.title) ? trimSentence(rawAiSummary) : '';
if (aiSummary && looksTooGeneric(aiSummary, aiKeyChanges)) {
  aiSummary = '';
}
let summary = aiSummary || composeSummary(applicant || aiAuthor, aiKeyChanges, fallbackSummary);
summary = ensureAuthor(summary || fallbackSummary, applicant || aiAuthor);
summary = trimSentence(summary || fallbackSummary);

const textForAnalysis = `${payload.title || ''} ${applicant || ''} ${payload.stage || ''} ${payload.projectType || ''} ${summary} ${(aiKeyChanges || []).join(' ')} ${fallbackSummary}`.toLowerCase();

const strong = [
  'nauka','nauki','działalności naukowej','badania naukowe',
  'szkolnictwa wyższego','uczelnia','uczelnie','uczelniach',
  'student','studenci','doktorant','doktoranci',
  'nauczyciel akademicki','pracownik naukowy',
  'instytut badawczy','polska akademia nauk','pan',
  'ncn','narodowe centrum nauki','ncbir','narodowe centrum badań i rozwoju',
  'nawa','polska komisja akredytacyjna',
  'stopień doktora','tytuł profesora','stopni naukowych',
  'ewaluacja jakości działalności naukowej',
  'system informacji o szkolnictwie wyższym','pol-on','polon',
  'prawo o szkolnictwie wyższym i nauce'
];
const medium = [
  'kształcenie','studia','szkoła wyższa','szkoły wyższe',
  'pomoc materialna','stypendium','akademik','rektor','senat uczelni',
  'instytut','badawcz','laboratorium','grant','granty',
  'transfer technologii','innowacje','spin-off','startup akademicki'
];
const negative = [
  'szkoła podstawowa','przedszkole','żłobek','liceum','technikum',
  'matura','egzamin ósmoklasisty','szkoła branżowa'
];

let score = 0;
const hitsStrong = [], hitsMedium = [], hitsNegative = [];
for (const kw of strong) { if (textForAnalysis.includes(kw)) { score += 3; hitsStrong.push(kw); } }
for (const kw of medium) { if (textForAnalysis.includes(kw)) { score += 1; hitsMedium.push(kw); } }
for (const kw of negative) { if (textForAnalysis.includes(kw)) { score -= 2; hitsNegative.push(kw); } }

if (applicant.toLowerCase().includes('minister nauki')) score += 6;
if (applicant.toLowerCase().includes('minister edukacji')) score -= 1;
if (/polska akademia nauk|ncn|ncbir|nawa/i.test(textForAnalysis)) score += 4;

const created = parseDatePL(payload.dateCreated);
const now = new Date();
const ageDays = created ? Math.floor((now - created) / 86400000) : null;
const daysLookback = Number(payload.daysLookback || 14);
const withinLookback = ageDays === null ? true : ageDays <= daysLookback;

const threshold = Number(payload.scoreThreshold || 4);
const isRelevant = score >= threshold;

const staticData = $getWorkflowStaticData('global');
if (!staticData.sentProjects) staticData.sentProjects = {};
if (!Array.isArray(staticData.currentRunProjects)) staticData.currentRunProjects = [];

const projectId = payload.projectId || payload.url;
const fingerprint = [payload.title || '', payload.dateUpdated || '', payload.stage || '', payload.documentUrl || '', summary].join('|');
const alreadySent = staticData.sentProjects[projectId] && staticData.sentProjects[projectId].fingerprint === fingerprint;
const includeInMain = withinLookback && isRelevant && !alreadySent;

const why = [];
if (applicant.toLowerCase().includes('minister nauki')) why.push('wnioskodawcą jest Minister Nauki lub Minister Nauki i Szkolnictwa Wyższego');
if (hitsStrong.some(h => ['nauka','nauki','badania naukowe','działalności naukowej'].includes(h))) why.push('projekt zawiera bezpośrednie odniesienia do nauki lub badań naukowych');
if (hitsStrong.some(h => ['szkolnictwa wyższego','uczelnia','uczelnie','student','doktorant','nauczyciel akademicki'].includes(h))) why.push('projekt wpływa na szkolnictwo wyższe, uczelnie, studentów lub doktorantów');
if (textForAnalysis.includes('prawo o szkolnictwie wyższym i nauce')) why.push('projekt odwołuje się do ustawy Prawo o szkolnictwie wyższym i nauce');
if (/polska akademia nauk|ncn|ncbir|nawa/i.test(textForAnalysis)) why.push('projekt dotyczy instytucji systemu nauki i szkolnictwa wyższego');
if (!why.length) why.push('projekt nie spełnił szczególnych kryteriów MNiSW, ale został ujęty w przeglądzie RCL');

if (includeInMain) {
  staticData.sentProjects[projectId] = {
    fingerprint,
    seenAt: new Date().toISOString()
  };
}

const result = {
  projectId,
  title: payload.title,
  applicant,
  stage: payload.stage,
  number: payload.number,
  projectType: payload.projectType,
  dateCreated: payload.dateCreated,
  dateUpdated: payload.dateUpdated,
  summary,
  fallbackSummary,
  aiSummary,
  aiAuthor,
  keyChanges: aiKeyChanges,
  sourceQuality: aiSourceQuality || payload.summarySource || '',
  whyRelevant: why.join('; '),
  score,
  url: payload.url,
  fromEmail: payload.fromEmail,
  toEmail: payload.toEmail,
  isRelevant,
  withinLookback,
  alreadySent: Boolean(alreadySent),
  includeInMain,
  summarySource: aiSummary ? 'ai-summary' : payload.summarySource,
  documentUrl: payload.documentUrl,
  documentLabel: payload.documentLabel
};

staticData.currentRunProjects.push(result);
return { json: result };

function cleanText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function normalizeKeyChanges(value) {
  if (!Array.isArray(value)) return [];
  return value.map(v => cleanText(v)).filter(Boolean).slice(0, 4);
}

function renderMetaHtml(parts) {
  const filtered = parts.filter(Boolean);
  if (!filtered.length) return '';
  return filtered
    .map(v => `<span style="display:inline-block;font-size:12px;line-height:1.5;color:#64748b;margin-right:0">${escapeHtml(v)}</span>`)
    .join('<span style="display:inline-block;font-size:12px;line-height:1.5;color:#cbd5e1;padding:0 8px">|</span>');
}

function renderMetaText(parts) {
  const filtered = parts.filter(Boolean).map(v => cleanText(v)).filter(Boolean);
  return filtered.length ? filtered.join(' | ') : null;
}

function renderKeyChangesHtml(changes, tone = 'blue') {
  const items = normalizeKeyChanges(changes);
  if (!items.length) return '';
  const accent = tone === 'amber' ? '#b45309' : '#1d4ed8';
  const background = tone === 'amber' ? '#fff7ed' : '#eff6ff';
  const border = tone === 'amber' ? '#f59e0b' : '#93c5fd';
  return `
<div style="margin-top:14px;background:${background};border-radius:10px;padding:12px 14px;border:1px solid ${border}">
  <div style="font-size:11px;font-weight:700;color:${accent};text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">Kluczowe zmiany</div>
  <ul style="margin:0;padding-left:18px;color:#334155;font-size:13px;line-height:1.7">
    ${items.map(item => `<li style="margin-bottom:4px">${escapeHtml(item)}</li>`).join('')}
  </ul>
</div>`;
}

function renderKeyChangesText(changes) {
  const items = normalizeKeyChanges(changes);
  if (!items.length) return null;
  return `Kluczowe zmiany: ${items.join('; ')}`;
}

function renderFooterHtml(dateStr) {
  return `<div style="margin-top:24px;background:#ffffff;border:1px solid #e2e8f0;border-radius:12px;padding:18px 20px;text-align:center">
    <div style="font-size:12px;font-weight:700;letter-spacing:.8px;text-transform:uppercase;color:#1e3a5f;margin-bottom:6px">Monitor Legislacyjny · MNiSW</div>
    <div style="font-size:13px;color:#475569;line-height:1.6">Made by Michał Reczek · <a href="mailto:michalreczek@gmail.com" style="color:#1d4ed8;text-decoration:none">michalreczek@gmail.com</a></div>
    <div style="font-size:11px;color:#94a3b8;margin-top:8px">Źródło: strona główna legislacja.gov.pl · ${escapeHtml(dateStr)}</div>
  </div>`;
}

function renderFooterText(dateStr) {
  return [
    'Monitor Legislacyjny - MNiSW',
    'Made by Michał Reczek',
    'Kontakt: michalreczek@gmail.com',
    `Źródło: strona główna legislacja.gov.pl | ${dateStr}`
  ].join('\n');
}

const staticData = $getWorkflowStaticData('global');
const analysed = (Array.isArray(staticData.currentRunProjects) ? staticData.currentRunProjects : [])
  .filter(i =>
    i &&
    typeof i.title === 'string' && i.title.trim() &&
    typeof i.summary === 'string' && i.summary.trim() &&
    typeof i.url === 'string' && i.url.trim()
  );

const extracted = $('Extract Recent Project URLs').all()
  .map(i => i.json)
  .filter(i =>
    i &&
    !i.error &&
    typeof i.projectUrl === 'string' && i.projectUrl.trim() &&
    typeof i.titleFromList === 'string' && i.titleFromList.trim()
  );

const metaSource = analysed.find(i => typeof i.fromEmail === 'string' && i.fromEmail.trim() && typeof i.toEmail === 'string' && i.toEmail.trim())
  || extracted.find(i => typeof i.fromEmail === 'string' && i.fromEmail.trim() && typeof i.toEmail === 'string' && i.toEmail.trim());

if (!metaSource) {
  return [];
}

const analysedByUrl = new Map(analysed.map(i => [i.url, i]));
const appendixProjects = [];
const seen = new Set();

for (const item of extracted) {
  const analysedItem = analysedByUrl.get(item.projectUrl);
  appendixProjects.push({
    title: analysedItem?.title || item.titleFromList,
    summary: analysedItem?.summary || 'Projekt widoczny w RCL, ale nie udało się pobrać treści uzasadnienia z aktywnego etapu.',
    url: item.projectUrl,
    dateCreated: analysedItem?.dateCreated || item.dateCreatedFromList || '',
    applicant: analysedItem?.applicant || '',
    number: analysedItem?.number || '',
    projectType: analysedItem?.projectType || '',
    stage: analysedItem?.stage || '',
    whyRelevant: analysedItem?.whyRelevant || 'Pozycja ujęta w zbiorczym przeglądzie projektów widocznych w RCL.',
    score: analysedItem?.score || 0,
    includeInMain: Boolean(analysedItem?.includeInMain),
    keyChanges: normalizeKeyChanges(analysedItem?.keyChanges || [])
  });
  seen.add(item.projectUrl);
}

for (const item of analysed) {
  if (seen.has(item.url)) continue;
  appendixProjects.push({
    title: item.title,
    summary: item.summary,
    url: item.url,
    dateCreated: item.dateCreated || '',
    applicant: item.applicant || '',
    number: item.number || '',
    projectType: item.projectType || '',
    stage: item.stage || '',
    whyRelevant: item.whyRelevant || 'Pozycja ujęta w zbiorczym przeglądzie projektów widocznych w RCL.',
    score: item.score || 0,
    includeInMain: Boolean(item.includeInMain),
    keyChanges: normalizeKeyChanges(item.keyChanges || [])
  });
}

if (!appendixProjects.length) {
  return [];
}

const mainItems = appendixProjects
  .filter(i => i.includeInMain)
  .sort((a, b) => (b.score || 0) - (a.score || 0));

const allProjects = appendixProjects;
const today = new Date();
const dateStr = today.toISOString().slice(0, 10);

const statsCards = `
<div style="margin-top:22px;display:flex;gap:18px;flex-wrap:wrap">
  <div style="min-width:150px;background:rgba(255,255,255,.14);border:1px solid rgba(255,255,255,.18);box-shadow:inset 0 1px 0 rgba(255,255,255,.08);border-radius:12px;padding:14px 22px;text-align:center">
    <div style="font-size:30px;font-weight:800;line-height:1">${mainItems.length}</div>
    <div style="font-size:11px;opacity:.82;margin-top:8px;text-transform:uppercase;letter-spacing:.8px">W sekcji głównej</div>
  </div>
  <div style="min-width:150px;background:rgba(255,255,255,.14);border:1px solid rgba(255,255,255,.18);box-shadow:inset 0 1px 0 rgba(255,255,255,.08);border-radius:12px;padding:14px 22px;text-align:center">
    <div style="font-size:30px;font-weight:800;line-height:1">${allProjects.length}</div>
    <div style="font-size:11px;opacity:.82;margin-top:8px;text-transform:uppercase;letter-spacing:.8px">Łącznie w RCL</div>
  </div>
</div>`;

const mainCards = mainItems.length
  ? mainItems.map((p, idx) => `
<div style="background:#fff;border:1px solid #dbe4f0;border-radius:14px;padding:22px 22px 20px;margin-bottom:18px;box-shadow:0 8px 24px rgba(15,23,42,.04)">
  <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:12px">
    <span style="background:#dbeafe;color:#1d4ed8;border-radius:999px;padding:4px 11px;font-size:12px;font-weight:700">#${idx + 1}</span>
    ${p.number ? `<span style="background:#f8fafc;color:#475569;border:1px solid #e2e8f0;border-radius:999px;padding:4px 11px;font-size:12px">${escapeHtml(p.number)}</span>` : ''}
    ${p.projectType ? `<span style="background:#f8fafc;color:#475569;border:1px solid #e2e8f0;border-radius:999px;padding:4px 11px;font-size:12px">${escapeHtml(p.projectType)}</span>` : ''}
  </div>
