const appendixCards = allProjects.map((p, idx) => `
<div style="background:#ffffff;border:1px solid #d9dee8;border-radius:12px;padding:16px 16px 15px;margin-bottom:14px;">
  <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:10px;">
