const newline = '\n';
const separator = '\n\n---\n\n';

const mainText = mainItems.length
  ? mainItems.map((p, idx) => [
      `${idx + 1}. ${p.title}`,
      `Link: ${p.url}`,
      renderMetaText([p.dateCreated, p.applicant, p.stage]),
      p.number ? `Numer: ${p.number}` : null,
      p.projectType ? `Rodzaj: ${p.projectType}` : null,
      `Dlaczego MNiSW: ${p.whyRelevant}`,
      `Streszczenie: ${p.summary}`,
      renderKeyChangesText(p.keyChanges)
    ].filter(Boolean).join(newline)).join(separator)
  : 'Brak nowych projektów mieszczących się we właściwości Ministra Nauki i Szkolnictwa Wyższego albo wyraźnie wpływających na ten obszar.';

const appendixText = allProjects.map((p, idx) => [
  `${idx + 1}. ${p.title}`,
  `Link: ${p.url}`,
  renderMetaText([p.dateCreated, p.applicant]),
  `Krótki opis: ${p.summary}`,
  renderKeyChangesText(p.keyChanges)
].filter(Boolean).join(newline)).join(separator);

const subject = mainItems.length
  ? `Monitor MNiSW | ${mainItems.length} nowych projektów – ${dateStr}`
  : `Monitor MNiSW | Przegląd RCL – ${dateStr}`;

staticData.currentRunProjects = [];

return [{
  json: {
    subject,
    html,
    text: `Monitor Legislacyjny - MNiSW\nData: ${dateStr}\nSekcja główna: ${mainItems.length}\nŁącznie w RCL: ${allProjects.length}\n\nSekcja główna\n${mainText}\n\nNajnowsze projekty w RCL\n${appendixText}\n\n${renderFooterText(dateStr)}`,
    fromEmail: metaSource.fromEmail,
    toEmail: metaSource.toEmail
  }
}];
